import Header from './components/Header';
import ProjectCard from './components/ProjectCard';

function App() {
  return (
    <div>
    <Header />
    <h2>Mis Proyectos</h2>
    <div>
      {projects.map((project, index) => (
        <ProjectCard
          key={index}
          title={project.title}
          description={project.description}
          link={project.link}
        />
      ))}
    </div>
  </div>
  );
}

export default App;
